class Solution:
    def sortedSquares(self, nums: List[int]) -> List[int]:
        n = len(nums)
        result = [0] * n
        left = 0
        right = n - 1

        for write in range(n - 1, -1, -1):
            if nums[left] ** 2 < nums[right] ** 2:
                result[write] = nums[right] ** 2
                right -= 1
            else:
                result[write] = nums[left] ** 2
                left += 1
        return result

class Solution:
    def partition(self, s: str) -> list[list[str]]:
        result: list[list[str]] = []
        path: list[str] = []

        def is_palindrome(left: int, right: int) -> bool:
            while left < right:
                if s[left] != s[right]:
                    return False
                left += 1
                right -= 1
            return True

        def backtrack(start: int) -> None:
            if start == len(s):
                result.append(path.copy())
                return
            for end in range(start, len(s)):
                if is_palindrome(start, end):
                    path.append(s[start : end + 1])
                    backtrack(end + 1)
                    path.pop()

        backtrack(0)
        return result

class Solution:
    def letterCombinations(self, digits: str) -> list[str]:
        if not digits:
            return []
        mapping = {
            "2": "abc",
            "3": "def",
            "4": "ghi",
            "5": "jkl",
            "6": "mno",
            "7": "pqrs",
            "8": "tuv",
            "9": "wxyz",
        }
        result: list[str] = []
        path: list[str] = []

        def backtrack(index: int) -> None:
            if index == len(digits):
                result.append("".join(path))
                return
            for ch in mapping[digits[index]]:
                path.append(ch)
                backtrack(index + 1)
                path.pop()

        backtrack(0)
        return result

class Solution:
    def combinationSum3(self, k: int, n: int) -> list[list[int]]:
        result: list[list[int]] = []
        path: list[int] = []

        def backtrack(start: int, remaining: int) -> None:
            if len(path) == k:
                if remaining == 0:
                    result.append(path.copy())
                return
            for i in range(start, 10):
                if i > remaining:
                    break
                path.append(i)
                backtrack(i + 1, remaining - i)
                path.pop()

        backtrack(1, n)
        return result

from collections import defaultdict

class Solution:
    def findItinerary(self, tickets: list[list[str]]) -> list[str]:
        graph: dict[str, list[str]] = defaultdict(list)
        for src, dst in sorted(tickets, reverse=True):
            graph[src].append(dst)
        route: list[str] = []

        def visit(airport: str) -> None:
            while graph[airport]:
                visit(graph[airport].pop())
            route.append(airport)

        visit("JFK")
        return route[::-1]

class Solution:
    def solveSudoku(self, board: list[list[str]]) -> None:
        rows = [set() for _ in range(9)]
        cols = [set() for _ in range(9)]
        boxes = [set() for _ in range(9)]
        empties: list[tuple[int, int]] = []

        for r in range(9):
            for c in range(9):
                value = board[r][c]
                if value == ".":
                    empties.append((r, c))
                else:
                    rows[r].add(value)
                    cols[c].add(value)
                    boxes[(r // 3) * 3 + (c // 3)].add(value)

        def backtrack(index: int) -> bool:
            if index == len(empties):
                return True
            r, c = empties[index]
            b = (r // 3) * 3 + (c // 3)
            for digit in map(str, range(1, 10)):
                if digit in rows[r] or digit in cols[c] or digit in boxes[b]:
                    continue
                board[r][c] = digit
                rows[r].add(digit)
                cols[c].add(digit)
                boxes[b].add(digit)
                if backtrack(index + 1):
                    return True
                board[r][c] = "."
                rows[r].remove(digit)
                cols[c].remove(digit)
                boxes[b].remove(digit)
            return False

        backtrack(0)

