class Solution:
    def findBottomLeftValue(self, root: Optional[TreeNode]) -> int:
        queue: deque[TreeNode] = deque([root])
        leftmost = root.val
        while queue:
            leftmost = queue[0].val
            for _ in range(len(queue)):
                node = queue.popleft()
                if node.left:
                    queue.append(node.left)
                if node.right:
                    queue.append(node.right)
        return leftmost

