class Solution:
    def convertBST(self, root: Optional[TreeNode]) -> Optional[TreeNode]:
        self.total = 0

        def traverse(node: Optional[TreeNode]) -> None:
            if node is None:
                return
            traverse(node.right)
            self.total += node.val
            node.val = self.total
            traverse(node.left)

        traverse(root)
        return root

