        raise ValueError("all embedding rows must have the same length")

    if not entity_ids:
        return [0.0] * embedding_dim
    if any(entity_id < 0 or entity_id >= len(embedding_table) for entity_id in entity_ids):
        raise ValueError("entity_ids must index valid embedding rows")

    pooled = [0.0] * embedding_dim
    for entity_id in entity_ids:
        row = embedding_table[entity_id]
        for index, value in enumerate(row):
            pooled[index] += value
    return [value / len(entity_ids) for value in pooled]

pub fn split_indices(n: usize, train_frac: f64, val_frac: f64) -> (Vec<usize>, Vec<usize>, Vec<usize>) {
    let n_train = (n as f64 * train_frac).floor() as usize;
    let n_val = (n as f64 * val_frac).floor() as usize;
    let train: Vec<usize> = (0..n_train).collect();
    let val: Vec<usize> = (n_train..(n_train + n_val)).collect();
    let test: Vec<usize> = (n_train + n_val..n).collect();
    (train, val, test)
}

def dead_relu_fraction(values: list[float]) -> float:
    if not values:
        return 0.0
    dead = sum(1 for v in values if v <= 0.0)
    return dead / len(values)

pub fn dead_relu_fraction(values: &[f64]) -> f64 {
    if values.is_empty() {
        return 0.0;
    }
    let dead = values.iter().filter(|v| **v <= 0.0).count();
    dead as f64 / values.len() as f64
}

import torch


class Value:
    """A tiny scalar wrapper that delegates all gradient work to PyTorch autograd."""

    def __init__(self, data, _tensor=None):
        # leaf node: create fresh tensor with grad; internal node: reuse tensor
        if _tensor is None:
            self._t = torch.tensor(float(data), dtype=torch.float64, requires_grad=True)
        else:
            self._t = _tensor

        # retain grad for non-leaf tensors too (so .grad is available for debugging)
        # Only call if tensor participates in autograd.
        if self._t.requires_grad:
            try:
                self._t.retain_grad()
            except RuntimeError:
                # In rare cases PyTorch can complain; safe to ignore for this tiny wrapper.
                pass

    # ------- conveniences -------
    @property
    def data(self):
        return float(self._t.item())

    @property
    def grad(self):
        g = self._t.grad
        return 0.0 if g is None else float(g.item())

    def __repr__(self):
        def fmt(x):
            return int(x) if float(x).is_integer() else round(float(x), 4)

        return f"Value(data={fmt(self.data)}, grad={fmt(self.grad)})"

    # ensure rhs is Value
    def _wrap(self, other):
        return other if isinstance(other, Value) else Value(other)

    # ------- arithmetic ops -------
    def __add__(self, other):
        other = self._wrap(other)
        return Value(0.0, _tensor=self._t + other._t)

    __radd__ = __add__

    def __mul__(self, other):
        other = self._wrap(other)
        return Value(0.0, _tensor=self._t * other._t)

    __rmul__ = __mul__

    # ------- activation -------
    def relu(self):
        return Value(0.0, _tensor=torch.relu(self._t))

    # ------- grad utilities -------
    def zero_grad(self):
        """
        Clear gradients for *this* node only.
        (If you want to clear an entire graph, keep references to leaves and clear those.)
        """
        if self._t.grad is not None:
            self._t.grad.zero_()

    # ------- back-prop entry -------
    def backward(self, retain_graph: bool = False):
        """
        Run autograd backward from this scalar output.
        Note: gradients accumulate unless you call zero_grad() on relevant nodes.
        """
        self._t.backward(retain_graph=retain_graph)

use std::cell::RefCell;
use std::collections::HashSet;
use std::rc::Rc;

#[derive(Clone)]
enum Op {
    Leaf,
    Add,
    Mul,
    Relu,
}

#[derive(Clone)]
pub struct Value {
    node: Rc<RefCell<Node>>,
}

#[derive(Clone)]
struct Node {
    data: f64,
    grad: f64,
    op: Op,
    left: Option<Value>,
    right: Option<Value>,
}

impl Value {
    pub fn new(data: f64) -> Self {
        Self {
            node: Rc::new(RefCell::new(Node {
                data,
                grad: 0.0,
                op: Op::Leaf,
                left: None,
                right: None,
            })),
        }
    }

    fn from_unary(data: f64, op: Op, left: Value) -> Self {
        Self {
            node: Rc::new(RefCell::new(Node {
                data,
                grad: 0.0,
                op,
                left: Some(left),
                right: None,
            })),
        }
    }

    fn from_binary(data: f64, op: Op, left: Value, right: Value) -> Self {
        Self {
            node: Rc::new(RefCell::new(Node {
                data,
                grad: 0.0,
                op,
                left: Some(left),
                right: Some(right),
            })),
        }
    }

    pub fn data(&self) -> f64 {
        self.node.borrow().data
    }

    pub fn grad(&self) -> f64 {
        self.node.borrow().grad
    }

    pub fn add(&self, other: &Value) -> Value {
        Value::from_binary(self.data() + other.data(), Op::Add, self.clone(), other.clone())
    }

    pub fn mul(&self, other: &Value) -> Value {
        Value::from_binary(self.data() * other.data(), Op::Mul, self.clone(), other.clone())
    }

    pub fn relu(&self) -> Value {
        Value::from_unary(self.data().max(0.0), Op::Relu, self.clone())
    }

    pub fn zero_grad(&self) {
        self.node.borrow_mut().grad = 0.0;
    }

    pub fn backward(&self) {
        let mut topo = Vec::new();
        let mut visited = HashSet::new();
        build_topo(self, &mut visited, &mut topo);

        // Match autograd's "accumulate gradients" behavior at the output seed.
        self.node.borrow_mut().grad += 1.0;

        for v in topo.into_iter().rev() {
            let (op, grad, left, right) = {
                let n = v.node.borrow();
                (n.op.clone(), n.grad, n.left.clone(), n.right.clone())
            };

            match op {
                Op::Leaf => {}
                Op::Add => {
                    if let Some(l) = left {
                        l.node.borrow_mut().grad += grad;
                    }
                    if let Some(r) = right {
                        r.node.borrow_mut().grad += grad;
                    }
                }
                Op::Mul => {
                    if let (Some(l), Some(r)) = (left, right) {
                        let l_data = l.data();
                        let r_data = r.data();
                        l.node.borrow_mut().grad += r_data * grad;
                        r.node.borrow_mut().grad += l_data * grad;
                    }
                }
                Op::Relu => {
                    if let Some(l) = left {
                        let local = if l.data() > 0.0 { 1.0 } else { 0.0 };
                        l.node.borrow_mut().grad += local * grad;
                    }
                }
            }
        }
    }
}

fn build_topo(v: &Value, visited: &mut HashSet<usize>, topo: &mut Vec<Value>) {
    let id = Rc::as_ptr(&v.node) as usize;
    if visited.insert(id) {
        let (left, right) = {
            let n = v.node.borrow();
            (n.left.clone(), n.right.clone())
        };
        if let Some(l) = left {
            build_topo(&l, visited, topo);
        }
        if let Some(r) = right {
            build_topo(&r, visited, topo);
        }
        topo.push(v.clone());
    }
}

pub fn linear_backprop(x: f64, grad_out: f64) -> f64 {
    grad_out * x
}

pub fn cross_entropy(logits: &[f64], target: usize) -> f64 {
    let m = logits.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = logits.iter().map(|x| (x - m).exp()).collect();
    let sum: f64 = exps.iter().sum();
    let prob = exps[target] / sum;
    -prob.ln()
}

def dropout(x: list[float], p: float, seed: int = 0) -> list[float]:
    if not 0.0 <= p < 1.0:
        raise ValueError("p must satisfy 0 <= p < 1")

    out = []
    state = seed
    for v in x:
        state = (1103515245 * state + 12345) % (2**31)
        keep = (state / (2**31 - 1)) > p
        out.append(v / (1 - p) if keep else 0.0)
    return out

pub fn dropout(x: &[f64], p: f64, seed: u64) -> Vec<f64> {
    let mut out = Vec::with_capacity(x.len());
    let mut state = seed;
    for &v in x {
        state = (1103515245u64.wrapping_mul(state).wrapping_add(12345)) % (1u64 << 31);
        let keep = (state as f64 / ((1u64 << 31) - 1) as f64) > p;
        if keep {
            out.push(v / (1.0 - p));
        } else {
            out.push(0.0);
        }
    }
    out
}

def should_stop(losses: list[float], patience: int) -> bool:
    best = float("inf")
    bad = 0
    for loss in losses:
        if loss < best:
            best = loss
            bad = 0
        else:
            bad += 1
            if bad >= patience:
                return True
    return False

pub fn should_stop(losses: &[f64], patience: usize) -> bool {
    let mut best = f64::INFINITY;
    let mut bad = 0;
    for &loss in losses {
        if loss < best {
            best = loss;
            bad = 0;
        } else {
            bad += 1;
            if bad >= patience {
                return true;
            }
        }
    }
    false
}

from __future__ import annotations


def _matvec(w: list[list[float]], x: list[float]) -> list[float]:
    return [sum(w_row[j] * x[j] for j in range(len(x))) for w_row in w]


def _relu(x: list[float]) -> list[float]:
    return [max(0.0, v) for v in x]


def feedforward(
    x: list[float],
    weights: list[list[list[float]]],
    biases: list[list[float]],
) -> list[float]:
    h = x
    for w, b in zip(weights, biases):
        h = [v + b[i] for i, v in enumerate(_matvec(w, h))]
        h = _relu(h)
    return h

pub fn feedforward(
    x: &[f64],
    weights: &[Vec<Vec<f64>>],
    biases: &[Vec<f64>],
) -> Vec<f64> {
    let mut h: Vec<f64> = x.to_vec();
    for (w, b) in weights.iter().zip(biases.iter()) {
        let mut next = vec![0.0; w.len()];
        for i in 0..w.len() {
            let mut acc = 0.0;
            for j in 0..h.len() {
                acc += w[i][j] * h[j];
            }
            next[i] = (acc + b[i]).max(0.0);
        }
        h = next;
    }
    h
}

