pub fn he_normal(fan_in: usize, fan_out: usize, seed: u64) -> Vec<f64> {
    let std = (2.0 / fan_in as f64).sqrt();
    let mut values = Vec::new();
    let mut state = seed;
    while values.len() < fan_in * fan_out {
        state = (1103515245u64.wrapping_mul(state).wrapping_add(12345)) % (1u64 << 31);
        let u1 = (state as f64 / ((1u64 << 31) - 1) as f64).max(1e-6);
        state = (1103515245u64.wrapping_mul(state).wrapping_add(12345)) % (1u64 << 31);
        let u2 = state as f64 / ((1u64 << 31) - 1) as f64;
        let z0 = (-2.0 * u1.ln()).sqrt() * (2.0 * std::f64::consts::PI * u2).cos();
        let z1 = (-2.0 * u1.ln()).sqrt() * (2.0 * std::f64::consts::PI * u2).sin();
        values.push(z0 * std);
        if values.len() < fan_in * fan_out {
            values.push(z1 * std);
        }
    }
    values
}

def hinge_loss(score: float, label: int) -> float:
    if label not in (-1, 1):
        raise ValueError("label must be either -1 or 1")

    return max(0.0, 1 - label * score)

pub fn hinge_loss(score: f64, label: i32) -> f64 {
    let val = 1.0 - (label as f64) * score;
    if val > 0.0 { val } else { 0.0 }
}

def huber(y: float, y_hat: float, delta: float = 1.0) -> float:
    e = y - y_hat
    if abs(e) <= delta:
        return 0.5 * e * e
    return delta * (abs(e) - 0.5 * delta)

pub fn huber(y: f64, y_hat: f64, delta: f64) -> f64 {
    let e = y - y_hat;
    if e.abs() <= delta {
        0.5 * e * e
    } else {
        delta * (e.abs() - 0.5 * delta)
    }
}

fn softmax(logits: &[f64], temp: f64) -> Vec<f64> {
    let m = logits.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = logits.iter().map(|x| ((x - m) / temp).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

pub fn distill_loss(student: &[f64], teacher: &[f64], temp: f64) -> f64 {
    let ps = softmax(student, temp);
    let pt = softmax(teacher, temp);
    let mut loss = 0.0;
    for (p_s, p_t) in ps.iter().zip(pt.iter()) {
        if *p_t > 0.0 && *p_s > 0.0 {
            loss += p_t * (p_t / p_s).ln();
        }
    }
    loss
}

pub fn l1_penalty(weights: &[f64], lam: f64) -> f64 {
    lam * weights.iter().map(|w| w.abs()).sum::<f64>()
}

pub fn l2_penalty(weights: &[f64], lam: f64) -> f64 {
    lam * weights.iter().map(|w| w * w).sum::<f64>()
}

