import math


def label_smoothed_cross_entropy(
    probabilities: list[float],
    target_index: int,
    smoothing: float,
) -> float:
    if not probabilities:
        raise ValueError("probabilities must be non-empty")
    if any(probability <= 0.0 or probability > 1.0 for probability in probabilities):
        raise ValueError("probabilities must lie in (0, 1]")
    if not math.isclose(sum(probabilities), 1.0, rel_tol=1e-9, abs_tol=1e-9):
        raise ValueError("probabilities must sum to 1")
    if not 0.0 <= smoothing < 1.0:
        raise ValueError("smoothing must satisfy 0 <= smoothing < 1")
    if not 0 <= target_index < len(probabilities):
        raise ValueError("target_index must be in range")
    if len(probabilities) == 1:
        return -math.log(probabilities[0])

    off_target = smoothing / (len(probabilities) - 1)
    loss = 0.0
    for index, probability in enumerate(probabilities):
        target_probability = 1.0 - smoothing if index == target_index else off_target
        loss -= target_probability * math.log(probability)
    return loss

def mae(y: list[float], y_hat: list[float]) -> float:
    if len(y) != len(y_hat):
        raise ValueError("y and y_hat must have the same length")
    if not y:
        raise ValueError("inputs must be non-empty")

    return sum(abs(a - b) for a, b in zip(y, y_hat)) / len(y)

pub fn mae(y: &[f64], y_hat: &[f64]) -> f64 {
    let sum: f64 = y.iter().zip(y_hat.iter()).map(|(a, b)| (a - b).abs()).sum();
    sum / y.len() as f64
}

def mse(y: list[float], y_hat: list[float]) -> float:
    if len(y) != len(y_hat):
        raise ValueError("y and y_hat must have the same length")
    if not y:
        raise ValueError("inputs must be non-empty")

    return sum((a - b) ** 2 for a, b in zip(y, y_hat)) / len(y)

pub fn mse(y: &[f64], y_hat: &[f64]) -> f64 {
    let sum: f64 = y.iter().zip(y_hat.iter()).map(|(a, b)| (a - b).powi(2)).sum();
    sum / y.len() as f64
}

