from dataclasses import dataclass
import math


@dataclass(frozen=True)
class ABTestResult:
    control_rate: float
    treatment_rate: float
    relative_lift: float
    z_score: float
    p_value: float


def ab_test_analysis(
    control_conversions: int,
    control_trials: int,
    treatment_conversions: int,
    treatment_trials: int,
) -> ABTestResult:
    if control_trials <= 0 or treatment_trials <= 0:
        raise ValueError("trial counts must be positive")
    if not 0 <= control_conversions <= control_trials:
        raise ValueError("control_conversions must satisfy 0 <= conversions <= trials")
    if not 0 <= treatment_conversions <= treatment_trials:
        raise ValueError("treatment_conversions must satisfy 0 <= conversions <= trials")

    control_rate = control_conversions / control_trials
    treatment_rate = treatment_conversions / treatment_trials
    pooled_rate = (control_conversions + treatment_conversions) / (control_trials + treatment_trials)
    standard_error = math.sqrt(
        pooled_rate * (1.0 - pooled_rate) * (1.0 / control_trials + 1.0 / treatment_trials)
    )

    if standard_error == 0.0:
        z_score = 0.0
        p_value = 1.0
    else:
        z_score = (treatment_rate - control_rate) / standard_error
        p_value = math.erfc(abs(z_score) / math.sqrt(2.0))

    if control_rate == 0.0:
        relative_lift = 0.0 if treatment_rate == 0.0 else math.inf
    else:
        relative_lift = (treatment_rate - control_rate) / control_rate

    return ABTestResult(
        control_rate=control_rate,
        treatment_rate=treatment_rate,
        relative_lift=relative_lift,
        z_score=z_score,
        p_value=p_value,
    )

def accuracy(y_true: list[int], y_pred: list[int]) -> float:
    correct = sum(1 for a, b in zip(y_true, y_pred) if a == b)
    return correct / len(y_true)

pub fn accuracy(y_true: &[i32], y_pred: &[i32]) -> f64 {
    let mut correct = 0;
    for (a, b) in y_true.iter().zip(y_pred.iter()) {
        if a == b { correct += 1; }
    }
    correct as f64 / y_true.len() as f64
}

from __future__ import annotations


def agreement_rate(outcomes: list[str | int]) -> float:
    if not outcomes:
        return 0.0

    counts: dict[str | int, int] = {}
    for outcome in outcomes:
        counts[outcome] = counts.get(outcome, 0) + 1
    return max(counts.values()) / len(outcomes)


def cohen_kappa(confusion_matrix: list[list[int]]) -> float:
    if not confusion_matrix:
        return 0.0

    size = len(confusion_matrix)
    if any(len(row) != size for row in confusion_matrix):
        raise ValueError("confusion_matrix must be square")
    if any(value < 0 for row in confusion_matrix for value in row):
        raise ValueError("confusion_matrix counts must be non-negative")

    total = sum(sum(row) for row in confusion_matrix)
    if total == 0:
        return 0.0

    observed = sum(confusion_matrix[index][index] for index in range(size)) / total
    row_totals = [sum(row) for row in confusion_matrix]
    column_totals = [
        sum(confusion_matrix[row_index][column_index] for row_index in range(size))
        for column_index in range(size)
    ]
    expected = sum(row * column for row, column in zip(row_totals, column_totals)) / (total * total)
    if expected == 1.0:
        return 1.0 if observed == 1.0 else 0.0
    return (observed - expected) / (1.0 - expected)

from __future__ import annotations

import math


def _validate_binary_labels(labels: list[int]) -> None:
    if any(label not in {0, 1} for label in labels):
        raise ValueError("labels must contain only 0 or 1")


def positive_rate(labels: list[int]) -> float:
    _validate_binary_labels(labels)
    if not labels:
        return 0.0
    return sum(labels) / len(labels)


def base_rate_gap(group_a: list[int], group_b: list[int]) -> float:
    return positive_rate(group_a) - positive_rate(group_b)


def prevalence_delta(baseline_labels: list[int], comparison_labels: list[int]) -> float:
    return positive_rate(comparison_labels) - positive_rate(baseline_labels)


def prevalence_ratio(group_a: list[int], group_b: list[int]) -> float:
    rate_a = positive_rate(group_a)
    rate_b = positive_rate(group_b)
    if rate_b == 0.0:
        return 0.0 if rate_a == 0.0 else float("inf")
    return rate_a / rate_b


def risk_ratio(exposed_labels: list[int], baseline_labels: list[int]) -> float:
    return prevalence_ratio(exposed_labels, baseline_labels)


def base_rate_ratio(group_a: list[int], group_b: list[int]) -> float:
    return prevalence_ratio(group_a, group_b)


def prevalence_index(labels: list[int], baseline_rate: float) -> float:
    if not 0.0 <= baseline_rate <= 1.0:
        raise ValueError("baseline_rate must lie in [0, 1]")

    rate = positive_rate(labels)
    if baseline_rate == 0.0:
        return 0.0 if rate == 0.0 else float("inf")
    return rate / baseline_rate


def prevalence_odds(labels: list[int]) -> float:
    rate = positive_rate(labels)
    if rate == 1.0:
        return float("inf")
    return rate / (1.0 - rate)


def log_prevalence_ratio(group_a: list[int], group_b: list[int]) -> float:
    rate_a = positive_rate(group_a)
    rate_b = positive_rate(group_b)
    if rate_a == 0.0 and rate_b == 0.0:
        return 0.0
    if rate_b == 0.0:
        return float("inf")
    if rate_a == 0.0:
        return float("-inf")
    return math.log(rate_a / rate_b)


def log_risk_ratio(exposed_labels: list[int], baseline_labels: list[int]) -> float:
    return log_prevalence_ratio(exposed_labels, baseline_labels)


def log_relative_risk(exposed_labels: list[int], baseline_labels: list[int]) -> float:
    return log_prevalence_ratio(exposed_labels, baseline_labels)


def log_odds(labels: list[int]) -> float:
    rate = positive_rate(labels)
    if rate == 0.0:
        return float("-inf")
    if rate == 1.0:
        return float("inf")
    return math.log(rate / (1.0 - rate))


def _event_rate(event_count: int, total_count: int) -> float:
    if total_count < 0:
