def top_k_accuracy(predicted_rankings: list[list[int]], labels: list[int], k: int) -> float:
    if len(predicted_rankings) != len(labels):
        raise ValueError("predicted_rankings and labels must have the same length")
    if k <= 0:
        raise ValueError("k must be positive")
    if not labels:
        return 0.0

    correct = 0
    for ranking, label in zip(predicted_rankings, labels):
        if label in ranking[:k]:
            correct += 1
    return correct / len(labels)


def macro_f1_score(
    true_positives: list[int],
    false_positives: list[int],
    false_negatives: list[int],
) -> float:
    if len(true_positives) != len(false_positives) or len(true_positives) != len(false_negatives):
        raise ValueError("all class-stat lists must have the same length")
    if any(value < 0 for value in true_positives + false_positives + false_negatives):
        raise ValueError("class statistics must be non-negative")
    if not true_positives:
        return 0.0

    total = 0.0
    for tp, fp, fn in zip(true_positives, false_positives, false_negatives):
        precision = 0.0 if tp + fp == 0 else tp / (tp + fp)
        recall = 0.0 if tp + fn == 0 else tp / (tp + fn)
        total += 0.0 if precision + recall == 0.0 else 2.0 * precision * recall / (precision + recall)
    return total / len(true_positives)


def micro_f1_score(
    true_positives: list[int],
    false_positives: list[int],
    false_negatives: list[int],
) -> float:
    if len(true_positives) != len(false_positives) or len(true_positives) != len(false_negatives):
        raise ValueError("all class-stat lists must have the same length")
    if any(value < 0 for value in true_positives + false_positives + false_negatives):
        raise ValueError("class statistics must be non-negative")
    if not true_positives:
        return 0.0

    tp = sum(true_positives)
    fp = sum(false_positives)
    fn = sum(false_negatives)
    denominator = 2 * tp + fp + fn
    return 0.0 if denominator == 0 else 2 * tp / denominator


def balanced_accuracy(true_positives: list[int], false_negatives: list[int]) -> float:
    if len(true_positives) != len(false_negatives):
        raise ValueError("true_positives and false_negatives must have the same length")
    if any(value < 0 for value in true_positives + false_negatives):
        raise ValueError("class statistics must be non-negative")
    if not true_positives:
        return 0.0

    total = 0.0
    for tp, fn in zip(true_positives, false_negatives):
        total += 0.0 if tp + fn == 0 else tp / (tp + fn)
    return total / len(true_positives)


def hamming_loss(predictions: list[list[int]], labels: list[list[int]]) -> float:
    if len(predictions) != len(labels):
        raise ValueError("predictions and labels must have the same length")
    if not labels:
        return 0.0

    total_positions = 0
    mismatches = 0
    for prediction_row, label_row in zip(predictions, labels):
        if len(prediction_row) != len(label_row):
            raise ValueError("each prediction row must match its label row length")
        if any(value not in {0, 1} for value in prediction_row + label_row):
            raise ValueError("predictions and labels must be binary")

        total_positions += len(label_row)
        mismatches += sum(prediction != label for prediction, label in zip(prediction_row, label_row))
    return 0.0 if total_positions == 0 else mismatches / total_positions


def log_loss(labels: list[int], probabilities: list[float], eps: float = 1.0e-15) -> float:
    if len(labels) != len(probabilities):
        raise ValueError("labels and probabilities must have the same length")
    if any(label not in {0, 1} for label in labels):
        raise ValueError("labels must be binary")
    if any(probability < 0.0 or probability > 1.0 for probability in probabilities):
        raise ValueError("probabilities must satisfy 0 <= p <= 1")
    if eps <= 0.0:
        raise ValueError("eps must be positive")
    if not labels:
        return 0.0

    total = 0.0
    for label, probability in zip(labels, probabilities):
        clipped = min(max(probability, eps), 1.0 - eps)
        total += label * math.log(clipped) + (1 - label) * math.log(1.0 - clipped)
    return -total / len(labels)

def confusion_matrix(y_true: list[int], y_pred: list[int]) -> list[list[int]]:
    tn = sum(1 for t, p in zip(y_true, y_pred) if t == 0 and p == 0)
    fp = sum(1 for t, p in zip(y_true, y_pred) if t == 0 and p == 1)
    fn = sum(1 for t, p in zip(y_true, y_pred) if t == 1 and p == 0)
    tp = sum(1 for t, p in zip(y_true, y_pred) if t == 1 and p == 1)
    return [[tn, fp], [fn, tp]]

pub fn confusion_matrix(y_true: &[i32], y_pred: &[i32]) -> [[i32; 2]; 2] {
    let mut tn = 0;
    let mut fp = 0;
    let mut fn_ = 0;
    let mut tp = 0;
    for (t, p) in y_true.iter().zip(y_pred.iter()) {
        if *t == 0 && *p == 0 { tn += 1; }
        if *t == 0 && *p == 1 { fp += 1; }
        if *t == 1 && *p == 0 { fn_ += 1; }
        if *t == 1 && *p == 1 { tp += 1; }
    }
    [[tn, fp], [fn_, tp]]
}

pub fn davies_bouldin(si: f64, sj: f64, dij: f64) -> f64 {
    if dij > 0.0 { (si + sj) / dij } else { 0.0 }
}

from __future__ import annotations

from dataclasses import dataclass
import math


@dataclass(frozen=True)
class DeLongResult:
    auc_a: float
    auc_b: float
    auc_difference: float
    z_score: float
    p_value: float


def _pair_score(positive_score: float, negative_score: float) -> float:
    if positive_score > negative_score:
        return 1.0
    if positive_score == negative_score:
        return 0.5
    return 0.0


def _sample_variance(values: list[float]) -> float:
    if len(values) <= 1:
        return 0.0
    mean = sum(values) / len(values)
    return sum((value - mean) ** 2 for value in values) / (len(values) - 1)


def _auc_components(positive_scores: list[float], negative_scores: list[float]) -> tuple[float, list[float], list[float]]:
    v10: list[float] = []
    for positive_score in positive_scores:
        v10.append(
            sum(_pair_score(positive_score, negative_score) for negative_score in negative_scores) / len(negative_scores)
        )

    v01: list[float] = []
    for negative_score in negative_scores:
        v01.append(
            sum(_pair_score(positive_score, negative_score) for positive_score in positive_scores) / len(positive_scores)
        )

    auc = sum(v10) / len(v10)
    return auc, v10, v01


def delong_auc_test(labels: list[int], scores_a: list[float], scores_b: list[float]) -> DeLongResult:
    if len(labels) != len(scores_a) or len(labels) != len(scores_b):
        raise ValueError("labels, scores_a, and scores_b must have the same length")
    if not labels:
        raise ValueError("labels must be non-empty")
    if any(label not in (0, 1) for label in labels):
        raise ValueError("labels must be binary")

    positive_indices = [index for index, label in enumerate(labels) if label == 1]
    negative_indices = [index for index, label in enumerate(labels) if label == 0]

    if not positive_indices or not negative_indices:
        raise ValueError("labels must contain both positive and negative examples")

    positive_scores_a = [scores_a[index] for index in positive_indices]
    negative_scores_a = [scores_a[index] for index in negative_indices]
    positive_scores_b = [scores_b[index] for index in positive_indices]
    negative_scores_b = [scores_b[index] for index in negative_indices]

    auc_a, v10_a, v01_a = _auc_components(positive_scores_a, negative_scores_a)
    auc_b, v10_b, v01_b = _auc_components(positive_scores_b, negative_scores_b)

    v10_diff = [component_a - component_b for component_a, component_b in zip(v10_a, v10_b)]
    v01_diff = [component_a - component_b for component_a, component_b in zip(v01_a, v01_b)]
    variance = _sample_variance(v10_diff) / len(v10_diff) + _sample_variance(v01_diff) / len(v01_diff)
    auc_difference = auc_a - auc_b

    if variance <= 0.0:
        z_score = 0.0
        p_value = 1.0
    else:
        z_score = auc_difference / math.sqrt(variance)
        p_value = math.erfc(abs(z_score) / math.sqrt(2.0))

    return DeLongResult(
        auc_a=auc_a,
        auc_b=auc_b,
        auc_difference=auc_difference,
        z_score=z_score,
        p_value=p_value,
    )

def dice(a: set[int], b: set[int]) -> float:
    inter = len(a & b)
    return 2 * inter / (len(a) + len(b)) if (len(a) + len(b)) > 0 else 0.0

use std::collections::HashSet;

pub fn dice(a: &HashSet<i32>, b: &HashSet<i32>) -> f64 {
    let inter = a.intersection(b).count() as f64;
    let denom = (a.len() + b.len()) as f64;
    if denom == 0.0 { 0.0 } else { 2.0 * inter / denom }
}

def f1_score(precision: float, recall: float) -> float:
    if precision + recall == 0:
        return 0.0
    return 2 * precision * recall / (precision + recall)

pub fn f1_score(precision: f64, recall: f64) -> f64 {
    if precision + recall == 0.0 { 0.0 } else { 2.0 * precision * recall / (precision + recall) }
}

from collections import Counter


def gini(labels: list[int]) -> float:
    counts = Counter(labels)
    n = len(labels)
    return 1 - sum((c / n) ** 2 for c in counts.values())

use std::collections::HashMap;

pub fn gini(labels: &[i32]) -> f64 {
    let mut counts: HashMap<i32, usize> = HashMap::new();
    for label in labels {
        *counts.entry(*label).or_insert(0) += 1;
    }
    let n = labels.len() as f64;
    let mut sum_sq = 0.0;
    for cnt in counts.values() {
        let p = *cnt as f64 / n;
        sum_sq += p * p;
    }
    1.0 - sum_sq
}

use std::collections::HashSet;

pub fn jaccard(a: &HashSet<i32>, b: &HashSet<i32>) -> f64 {
    let inter = a.intersection(b).count() as f64;
    let union = a.union(b).count() as f64;
    if union == 0.0 { 0.0 } else { inter / union }
}

