def mcc(tp: int, tn: int, fp: int, fn: int) -> float:
    denom = math.sqrt((tp + fp) * (tp + fn) * (tn + fp) * (tn + fn))
    if denom == 0:
        return 0.0
    return (tp * tn - fp * fn) / denom

pub fn mcc(tp: i32, tn: i32, fp: i32, fn_: i32) -> f64 {
    let denom = ((tp + fp) as f64 * (tp + fn_) as f64 * (tn + fp) as f64 * (tn + fn_) as f64).sqrt();
    if denom == 0.0 { 0.0 } else { (tp * tn - fp * fn_) as f64 / denom }
}

from __future__ import annotations


def pr_auc(recall: list[float], precision: list[float]) -> float:
    if len(recall) != len(precision):
        raise ValueError("recall and precision must have the same length")
    if not recall:
        return 0.0
    if any(not 0.0 <= value <= 1.0 for value in recall + precision):
        raise ValueError("recall and precision values must lie in [0, 1]")

    area = 0.0
    for index in range(1, len(recall)):
        if recall[index] < recall[index - 1]:
            raise ValueError("recall must be sorted in nondecreasing order")
        width = recall[index] - recall[index - 1]
        height = (precision[index] + precision[index - 1]) / 2.0
        area += width * height
    return area

pub fn precision_recall(y_true: &[i32], y_pred: &[i32]) -> (f64, f64) {
    let mut tp = 0;
    let mut fp = 0;
    let mut fn_ = 0;
    for (t, p) in y_true.iter().zip(y_pred.iter()) {
        if *t == 1 && *p == 1 { tp += 1; }
        if *t == 0 && *p == 1 { fp += 1; }
        if *t == 1 && *p == 0 { fn_ += 1; }
    }
    let precision = if tp + fp > 0 { tp as f64 / (tp + fp) as f64 } else { 0.0 };
    let recall = if tp + fn_ > 0 { tp as f64 / (tp + fn_) as f64 } else { 0.0 };
    (precision, recall)
}

pub fn r2_score(y: &[f64], y_hat: &[f64]) -> f64 {
    let mean: f64 = y.iter().sum::<f64>() / y.len() as f64;
    let ss_res: f64 = y.iter().zip(y_hat.iter()).map(|(a, b)| (a - b).powi(2)).sum();
    let ss_tot: f64 = y.iter().map(|a| (a - mean).powi(2)).sum();
    if ss_tot > 0.0 { 1.0 - ss_res / ss_tot } else { 0.0 }
}

