def _normalize_answer(text: str) -> str:
    text = text.lower()
    text = "".join(character for character in text if character not in string.punctuation)
    text = re.sub(r"\b(a|an|the)\b", " ", text)
    return " ".join(text.split())


def _parse_number(text: str) -> float | None:
    normalized = text.strip().replace(",", "")
    try:
        return float(normalized)
    except ValueError:
        return None


def verify_answer(prediction: str, references: list[str], numeric_tolerance: float = 1.0e-6) -> bool:
    if numeric_tolerance < 0.0:
        raise ValueError("numeric_tolerance must be non-negative")
    if not references:
        return False

    normalized_prediction = _normalize_answer(prediction)
    numeric_prediction = _parse_number(prediction)

    for reference in references:
        if normalized_prediction == _normalize_answer(reference):
            return True

        numeric_reference = _parse_number(reference)
        if numeric_prediction is not None and numeric_reference is not None:
            if abs(numeric_prediction - numeric_reference) <= numeric_tolerance:
                return True

    return False

pub fn causal_mask(seq_len: usize) -> Vec<Vec<f64>> {
    let mut mask = vec![vec![0.0; seq_len]; seq_len];
    for i in 0..seq_len {
        for j in (i + 1)..seq_len {
            mask[i][j] = f64::NEG_INFINITY;
        }
    }
    mask
}

fn softmax(row: &[f64]) -> Vec<f64> {
    let m = row
        .iter()
        .copied()
        .fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

fn matmul(a: &[Vec<f64>], b: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = b[0].len();
    let mut out = vec![vec![0.0; cols]; rows];
    for i in 0..rows {
        for j in 0..cols {
            let mut acc = 0.0;
            for k in 0..b.len() {
                acc += a[i][k] * b[k][j];
            }
            out[i][j] = acc;
        }
    }
    out
}

fn transpose(a: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = a[0].len();
    let mut out = vec![vec![0.0; rows]; cols];
    for i in 0..rows {
        for j in 0..cols {
            out[j][i] = a[i][j];
        }
    }
    out
}

pub fn causal_self_attention(q: &[Vec<f64>], k: &[Vec<f64>], v: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let dk = k[0].len() as f64;
    let scores = matmul(q, &transpose(k));
    let mask = causal_mask(scores.len());
    let mut masked = scores.clone();
    for i in 0..scores.len() {
        for j in 0..scores[0].len() {
            masked[i][j] = scores[i][j] / dk.sqrt() + mask[i][j];
        }
    }
    let weights: Vec<Vec<f64>> = masked.iter().map(|row| softmax(row)).collect();
    matmul(&weights, v)
}

from __future__ import annotations

import math
import re
from collections import Counter


def _tokens(text: str) -> list[str]:
    return re.findall(r"[a-z0-9]+", text.lower())


def bleu1_meteor(
    candidate: str,
    reference: str,
) -> tuple[float, float]:
    candidate_tokens = _tokens(candidate)
    reference_tokens = _tokens(reference)
    if not candidate_tokens or not reference_tokens:
        raise ValueError("candidate and reference must contain at least one token")

    candidate_counts = Counter(candidate_tokens)
    reference_counts = Counter(reference_tokens)
    matches = sum(
        min(count, reference_counts[token]) for token, count in candidate_counts.items()
    )

    precision = matches / len(candidate_tokens)
    recall = matches / len(reference_tokens)

    brevity_penalty = 1.0
    if len(candidate_tokens) < len(reference_tokens):
        brevity_penalty = math.exp(1.0 - len(reference_tokens) / len(candidate_tokens))
    bleu1 = brevity_penalty * precision

    if precision == 0.0 or recall == 0.0:
        meteor = 0.0
    else:
        meteor = (10.0 * precision * recall) / (recall + 9.0 * precision)

    return bleu1, meteor

from __future__ import annotations

import math


def greedy_choice(scores: list[float]) -> int:
    if not scores:
        raise ValueError("scores must be non-empty")
    return max(range(len(scores)), key=lambda index: scores[index])


def temperature_probabilities(logits: list[float], temperature: float) -> list[float]:
    if temperature <= 0.0:
        raise ValueError("temperature must be positive")
    if not logits:
        return []

    scaled = [logit / temperature for logit in logits]
    max_scaled = max(scaled)
    exps = [math.exp(value - max_scaled) for value in scaled]
    total = sum(exps)
    return [value / total for value in exps]


def top_k_filter(probabilities: list[float], k: int) -> list[int]:
    if k <= 0:
        raise ValueError("k must be positive")
    if not probabilities:
        return []
    if any(probability < 0.0 for probability in probabilities):
        raise ValueError("probabilities must be non-negative")

    ranked = sorted(enumerate(probabilities), key=lambda item: item[1], reverse=True)
    return [index for index, _ in ranked[: min(k, len(ranked))]]


def top_p_filter(probabilities: list[float], p: float) -> list[int]:
    if not 0.0 < p <= 1.0:
        raise ValueError("p must satisfy 0 < p <= 1")
    if not probabilities:
        return []
    if any(probability < 0.0 for probability in probabilities):
        raise ValueError("probabilities must be non-negative")

    total = sum(probabilities)
    if total <= 0.0:
        raise ValueError("probabilities must sum to a positive value")

    normalized = [probability / total for probability in probabilities]
    ranked = sorted(enumerate(normalized), key=lambda item: item[1], reverse=True)

    kept: list[int] = []
    cumulative = 0.0
    for index, probability in ranked:
        kept.append(index)
        cumulative += probability
        if cumulative >= p:
            break
    return kept


def sampling_pipeline_candidates(
    logits: list[float],
    temperature: float,
    top_k: int,
    top_p: float,
) -> list[int]:
    probabilities = temperature_probabilities(logits, temperature)
    if not probabilities:
        return []

    top_k_indices = top_k_filter(probabilities, top_k)
    top_k_probabilities = [probabilities[index] for index in top_k_indices]
    kept_relative = top_p_filter(top_k_probabilities, top_p)
    return [top_k_indices[index] for index in kept_relative]


def beam_search_step(
    beams: list[tuple[list[int], float]],
    next_token_log_probs: list[list[float]],
    beam_width: int,
) -> list[tuple[list[int], float]]:
    if len(beams) != len(next_token_log_probs):
        raise ValueError("beams and next_token_log_probs must have the same length")
    if beam_width <= 0:
        raise ValueError("beam_width must be positive")
    if not beams:
        return []

    candidates: list[tuple[list[int], float]] = []
    for (tokens, score), token_scores in zip(beams, next_token_log_probs):
        for token_id, token_log_prob in enumerate(token_scores):
            candidates.append((tokens + [token_id], score + token_log_prob))

    candidates.sort(key=lambda item: item[1], reverse=True)
    return candidates[:beam_width]

import math


def dpo_loss(delta_logp: float, delta_logp_ref: float, beta: float = 0.1) -> float:
    diff = beta * (delta_logp - delta_logp_ref)
    return -math.log(1 / (1 + math.exp(-diff)))

pub fn dpo_loss(delta_logp: f64, delta_logp_ref: f64, beta: f64) -> f64 {
    let diff = beta * (delta_logp - delta_logp_ref);
    -1.0 / (1.0 + (-diff).exp()).ln()
}

