pub fn quantize_fp(x: f64, mantissa_bits: i32) -> f64 {
    if x == 0.0 {
        return 0.0;
    }
    let exp = x.abs().log2().floor() as i32;
    let scale = 2f64.powi(mantissa_bits - exp);
    (x * scale).round() / scale
}

pub fn prune_heads(weights: &[Vec<f64>], keep: &[usize], head_dim: usize) -> Vec<Vec<f64>> {
    let mut out = Vec::with_capacity(weights.len());
    for row in weights {
        let mut new_row = Vec::new();
        for &h in keep {
            let start = h * head_dim;
            let end = start + head_dim;
            new_row.extend_from_slice(&row[start..end]);
        }
        out.push(new_row);
    }
    out
}

def quantize_int(x: float, bits: int, scale: float) -> int:
    qmax = 2 ** (bits - 1) - 1
    q = int(round(x / scale))
    return max(-qmax, min(qmax, q))

pub fn quantize_int(x: f64, bits: i32, scale: f64) -> i32 {
    let qmax = (1 << (bits - 1)) - 1;
    let q = (x / scale).round() as i32;
    q.max(-qmax).min(qmax)
}

