def kl_penalty(p: list[float], q: list[float], beta: float) -> float:
    kl = 0.0
    for pi, qi in zip(p, q):
        if pi > 0 and qi > 0:
            kl += pi * math.log(pi / qi)
    return beta * kl

pub fn kl_penalty(p: &[f64], q: &[f64], beta: f64) -> f64 {
    let mut kl = 0.0;
    for (&pi, &qi) in p.iter().zip(q.iter()) {
        if pi > 0.0 && qi > 0.0 {
            kl += pi * (pi / qi).ln();
        }
    }
    beta * kl
}

fn matmul(a: &[Vec<f64>], b: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = b[0].len();
    let mut out = vec![vec![0.0; cols]; rows];
    for i in 0..rows {
        for j in 0..cols {
            let mut acc = 0.0;
            for k in 0..b.len() {
                acc += a[i][k] * b[k][j];
            }
            out[i][j] = acc;
        }
    }
    out
}

pub fn lora_update(w: &[Vec<f64>], a: &[Vec<f64>], b: &[Vec<f64>], alpha: f64) -> Vec<Vec<f64>> {
    let r = b.len() as f64;
    let delta = matmul(a, b);
    let scale = alpha / r;
    let mut out = w.to_vec();
    for i in 0..w.len() {
        for j in 0..w[0].len() {
            out[i][j] += scale * delta[i][j];
        }
    }
    out
}

