import math


def _validate_matrix(a: list[list[float]], name: str) -> None:
    if not a or not a[0]:
        raise ValueError(f"{name} must be non-empty")
    width = len(a[0])
    if any(len(row) != width for row in a):
        raise ValueError(f"{name} must be rectangular")


def _softmax(row: list[float]) -> list[float]:
    m = max(row)
    exps = [math.exp(x - m) for x in row]
    s = sum(exps)
    return [e / s for e in exps]


def _matmul(a: list[list[float]], b: list[list[float]]) -> list[list[float]]:
    out = []
    for i in range(len(a)):
        row = []
        for j in range(len(b[0])):
            row.append(sum(a[i][k] * b[k][j] for k in range(len(b))))
        out.append(row)
    return out


def _transpose(a: list[list[float]]) -> list[list[float]]:
    return [list(col) for col in zip(*a)]


def _attention(q: list[list[float]], k: list[list[float]], v: list[list[float]]) -> list[list[float]]:
    dk = len(k[0])
    scores = _matmul(q, _transpose(k))
    scaled = [[val / math.sqrt(dk) for val in row] for row in scores]
    weights = [_softmax(row) for row in scaled]
    return _matmul(weights, v)


def multi_head_attention(q: list[list[float]], k: list[list[float]], v: list[list[float]], heads: int) -> list[list[float]]:
    _validate_matrix(q, "q")
    _validate_matrix(k, "k")
    _validate_matrix(v, "v")
    if heads <= 0:
        raise ValueError("heads must be positive")
    if len(q) != len(k) or len(k) != len(v):
        raise ValueError("q, k, and v must have the same sequence length")
    if len(q[0]) != len(k[0]) or len(k[0]) != len(v[0]):
        raise ValueError("q, k, and v must share the same model dimension")

    d_model = len(q[0])
    if d_model % heads != 0:
        raise ValueError("model dimension must be divisible by heads")

    head_dim = d_model // heads
    outputs = []
    for h in range(heads):
        q_h = [row[h * head_dim:(h + 1) * head_dim] for row in q]
        k_h = [row[h * head_dim:(h + 1) * head_dim] for row in k]
        v_h = [row[h * head_dim:(h + 1) * head_dim] for row in v]
        outputs.append(_attention(q_h, k_h, v_h))
    merged = []
    for i in range(len(q)):
        merged_row = []
        for h in range(heads):
            merged_row.extend(outputs[h][i])
        merged.append(merged_row)
    return merged

fn softmax(row: &[f64]) -> Vec<f64> {
    let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

fn matmul(a: &[Vec<f64>], b: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = b[0].len();
    let mut out = vec![vec![0.0; cols]; rows];
    for i in 0..rows {
        for j in 0..cols {
            let mut acc = 0.0;
            for k in 0..b.len() {
                acc += a[i][k] * b[k][j];
            }
            out[i][j] = acc;
        }
    }
    out
}

fn transpose(a: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = a[0].len();
    let mut out = vec![vec![0.0; rows]; cols];
    for i in 0..rows {
        for j in 0..cols {
            out[j][i] = a[i][j];
        }
    }
    out
}

fn attention(q: &[Vec<f64>], k: &[Vec<f64>], v: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let dk = k[0].len() as f64;
    let scores = matmul(q, &transpose(k));
    let scaled: Vec<Vec<f64>> = scores
        .iter()
        .map(|row| row.iter().map(|x| x / dk.sqrt()).collect())
        .collect();
    let weights: Vec<Vec<f64>> = scaled.iter().map(|row| softmax(row)).collect();
    matmul(&weights, v)
}

pub fn multi_head_attention(q: &[Vec<f64>], k: &[Vec<f64>], v: &[Vec<f64>], heads: usize) -> Vec<Vec<f64>> {
    let d_model = q[0].len();
    let head_dim = d_model / heads;
    let mut outputs: Vec<Vec<Vec<f64>>> = Vec::with_capacity(heads);
    for h in 0..heads {
        let start = h * head_dim;
        let end = (h + 1) * head_dim;
        let q_h: Vec<Vec<f64>> = q.iter().map(|row| row[start..end].to_vec()).collect();
        let k_h: Vec<Vec<f64>> = k.iter().map(|row| row[start..end].to_vec()).collect();
        let v_h: Vec<Vec<f64>> = v.iter().map(|row| row[start..end].to_vec()).collect();
        outputs.push(attention(&q_h, &k_h, &v_h));
    }
    let mut merged = vec![vec![0.0; d_model]; q.len()];
    for i in 0..q.len() {
        let mut offset = 0;
        for h in 0..heads {
            for val in &outputs[h][i] {
                merged[i][offset] = *val;
                offset += 1;
            }
        }
    }
    merged
}

from math import comb


def pass_at_k(total_samples: int, correct_samples: int, k: int) -> float:
    if total_samples <= 0 or k <= 0:
        raise ValueError("total_samples and k must be positive")
    if correct_samples < 0 or correct_samples > total_samples:
        raise ValueError("correct_samples must be in [0, total_samples]")
    if k > total_samples:
        raise ValueError("k cannot exceed total_samples")
    if correct_samples == 0:
        return 0.0
    if total_samples - correct_samples < k:
        return 1.0
    return 1.0 - comb(total_samples - correct_samples, k) / comb(total_samples, k)

