def _softmax(row: list[float]) -> list[float]:
    m = max(row)
    exps = [math.exp(x - m) for x in row]
    s = sum(exps)
    return [e / s for e in exps]


def next_token_loss(logits: list[list[float]], targets: list[int]) -> float:
    total = 0.0
    for row, tgt in zip(logits, targets):
        probs = _softmax(row)
        total += -math.log(probs[tgt])
    return total / len(targets)

pub fn next_token_loss(logits: &[Vec<f64>], targets: &[usize]) -> f64 {
    let mut total = 0.0;
    for (row, &tgt) in logits.iter().zip(targets.iter()) {
        let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
        let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
        let sum: f64 = exps.iter().sum();
        let prob = exps[tgt] / sum;
        total += -prob.ln();
    }
    total / targets.len() as f64
}

pub fn anchored_loss(align_loss: f64, ptx_loss: f64, alpha: f64) -> f64 {
    (1.0 - alpha) * align_loss + alpha * ptx_loss
}

