) -> list[tuple[str, float]]:
    if not 0.0 <= alpha <= 1.0:
        raise ValueError("alpha must satisfy 0 <= alpha <= 1")

    fused: dict[str, float] = {}
    for doc_id in set(sparse_scores) | set(dense_scores):
        fused[doc_id] = alpha * sparse_scores.get(doc_id, 0.0) + (1.0 - alpha) * dense_scores.get(doc_id, 0.0)

    return sorted(fused.items(), key=lambda item: item[1], reverse=True)

from __future__ import annotations


def retrieval_recall_at_k(retrieved_ids: list[str], relevant_ids: set[str], k: int) -> float:
    if k <= 0:
        raise ValueError("k must be positive")
    if not relevant_ids:
        return 0.0
    retrieved_top_k = set(retrieved_ids[:k])
    return len(retrieved_top_k & relevant_ids) / len(relevant_ids)


def retrieval_precision_at_k(retrieved_ids: list[str], relevant_ids: set[str], k: int) -> float:
    if k <= 0:
        raise ValueError("k must be positive")
    if not retrieved_ids:
        return 0.0
    retrieved_top_k = set(retrieved_ids[:k])
    return len(retrieved_top_k & relevant_ids) / k


def retrieval_f1_at_k(retrieved_ids: list[str], relevant_ids: set[str], k: int) -> float:
    if k <= 0:
        raise ValueError("k must be positive")
    if not relevant_ids:
        return 0.0

    retrieved_top_k = set(retrieved_ids[:k])
    precision = len(retrieved_top_k & relevant_ids) / k
    recall = len(retrieved_top_k & relevant_ids) / len(relevant_ids)
    if precision + recall == 0.0:
        return 0.0
    return 2.0 * precision * recall / (precision + recall)


def retrieval_hit_rate_at_k(
    query_retrievals: list[list[str]],
    query_relevants: list[set[str]],
    k: int,
) -> float:
    if len(query_retrievals) != len(query_relevants):
        raise ValueError("query_retrievals and query_relevants must have the same length")
    if k <= 0:
        raise ValueError("k must be positive")
    if not query_retrievals:
        return 0.0

    hits = 0
    for retrieved_ids, relevant_ids in zip(query_retrievals, query_relevants):
        if set(retrieved_ids[:k]) & relevant_ids:
            hits += 1
    return hits / len(query_retrievals)


def reciprocal_rank(relevance: list[int]) -> float:
    if any(label not in {0, 1} for label in relevance):
        raise ValueError("relevance labels must be binary")

    first_rank = next((index + 1 for index, label in enumerate(relevance) if label == 1), None)
    return 0.0 if first_rank is None else 1.0 / first_rank


def reranker_metrics(relevance: list[int], k: int) -> tuple[float, float]:
    if k <= 0:
        raise ValueError("k must be positive")
    if any(label not in {0, 1} for label in relevance):
        raise ValueError("relevance labels must be binary")
    if not relevance:
        return 0.0, 0.0

    top_k = relevance[:k]
    total_relevant = sum(relevance)
    recall = 0.0 if total_relevant == 0 else sum(top_k) / total_relevant
    return reciprocal_rank(top_k), recall


def rerank_gain(baseline_relevance: list[int], reranked_relevance: list[int]) -> float:
    return reciprocal_rank(reranked_relevance) - reciprocal_rank(baseline_relevance)


def rerank_disagreement_rate(
    baseline_ids: list[str],
    reranked_ids: list[str],
    k: int | None = None,
) -> float:
    if len(baseline_ids) != len(reranked_ids):
        raise ValueError("baseline_ids and reranked_ids must have the same length")
    if k is None:
        k = len(baseline_ids)
    if k <= 0:
        raise ValueError("k must be positive")
    if k > len(baseline_ids):
        raise ValueError("k cannot exceed ranking length")

    disagreements = sum(
        baseline_id != reranked_id
        for baseline_id, reranked_id in zip(baseline_ids[:k], reranked_ids[:k])
    )
    return disagreements / k

import math


def reward_model_loss(chosen: float, rejected: float) -> float:
    diff = chosen - rejected
    return -math.log(1 / (1 + math.exp(-diff)))

pub fn reward_model_loss(chosen: f64, rejected: f64) -> f64 {
    let diff = chosen - rejected;
    -1.0 / (1.0 + (-diff).exp()).ln()
}

from __future__ import annotations

import math


def _validate_matrix(a: list[list[float]], name: str) -> None:
    if not a or not a[0]:
        raise ValueError(f"{name} must be non-empty")
    width = len(a[0])
    if any(len(row) != width for row in a):
        raise ValueError(f"{name} must be rectangular")


def _softmax(row: list[float]) -> list[float]:
    m = max(row)
    exps = [math.exp(x - m) for x in row]
    s = sum(exps)
    return [e / s for e in exps]


def _matmul(a: list[list[float]], b: list[list[float]]) -> list[list[float]]:
    out = []
    for i in range(len(a)):
        row = []
        for j in range(len(b[0])):
            row.append(sum(a[i][k] * b[k][j] for k in range(len(b))))
        out.append(row)
    return out


def _transpose(a: list[list[float]]) -> list[list[float]]:
    return [list(col) for col in zip(*a)]


def self_attention(q: list[list[float]], k: list[list[float]], v: list[list[float]]) -> list[list[float]]:
    _validate_matrix(q, "q")
    _validate_matrix(k, "k")
    _validate_matrix(v, "v")
    if len(q) != len(k) or len(k) != len(v):
        raise ValueError("q, k, and v must have the same sequence length")
    if len(q[0]) != len(k[0]):
        raise ValueError("q and k must have the same feature dimension")

    dk = len(k[0])
    scores = _matmul(q, _transpose(k))
    scaled = [[val / math.sqrt(dk) for val in row] for row in scores]
    weights = [_softmax(row) for row in scaled]
    return _matmul(weights, v)

fn softmax(row: &[f64]) -> Vec<f64> {
    let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

fn matmul(a: &[Vec<f64>], b: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = b[0].len();
    let mut out = vec![vec![0.0; cols]; rows];
    for i in 0..rows {
        for j in 0..cols {
            let mut acc = 0.0;
            for k in 0..b.len() {
                acc += a[i][k] * b[k][j];
            }
            out[i][j] = acc;
        }
    }
    out
}

fn transpose(a: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = a[0].len();
    let mut out = vec![vec![0.0; rows]; cols];
    for i in 0..rows {
        for j in 0..cols {
            out[j][i] = a[i][j];
        }
    }
    out
}

pub fn self_attention(q: &[Vec<f64>], k: &[Vec<f64>], v: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let dk = k[0].len() as f64;
    let scores = matmul(q, &transpose(k));
    let scaled: Vec<Vec<f64>> = scores
        .iter()
        .map(|row| row.iter().map(|x| x / dk.sqrt()).collect())
        .collect();
    let weights: Vec<Vec<f64>> = scaled.iter().map(|row| softmax(row)).collect();
    matmul(&weights, v)
}

def window_mask(seq_len: int, window: int) -> list[list[int]]:
    mask = [[0 for _ in range(seq_len)] for _ in range(seq_len)]
    for i in range(seq_len):
        for j in range(seq_len):
            if abs(i - j) <= window:
                mask[i][j] = 1
    return mask

pub fn window_mask(seq_len: usize, window: usize) -> Vec<Vec<i32>> {
    let mut mask = vec![vec![0; seq_len]; seq_len];
    for i in 0..seq_len {
        for j in 0..seq_len {
            let dist = if i > j { i - j } else { j - i };
            if dist <= window {
                mask[i][j] = 1;
            }
        }
    }
    mask
}

def speculative_decode_step(
    draft_tokens: list[int],
    target_tokens: list[int],
) -> list[int]:
    if not target_tokens:
        raise ValueError("target_tokens must be non-empty")

    accepted = 0
    while (
        accepted < len(draft_tokens)
        and accepted < len(target_tokens)
        and draft_tokens[accepted] == target_tokens[accepted]
    ):
        accepted += 1

    if accepted < len(target_tokens):
        return target_tokens[: accepted + 1]
    return target_tokens[:]

pub fn sft_loss(logits: &[Vec<f64>], targets: &[usize], mask: &[u8]) -> f64 {
    let mut total = 0.0;
    let mut count = 0;
    for ((row, &tgt), &keep) in logits.iter().zip(targets.iter()).zip(mask.iter()) {
        if keep == 0 {
            continue;
        }
        let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
        let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
        let sum: f64 = exps.iter().sum();
        let prob = exps[tgt] / sum;
        total += -prob.ln();
        count += 1;
    }
    if count == 0 { 0.0 } else { total / count as f64 }
}

from __future__ import annotations

def build_vocab(texts: list[str]) -> dict[str, int]:
    vocab: dict[str, int] = {}
    for text in texts:
        for token in text.lower().split():
            if token not in vocab:
                vocab[token] = len(vocab)
    return vocab


def tokenize(text: str, vocab: dict[str, int]) -> list[int]:
    return [vocab[token] for token in text.lower().split() if token in vocab]

use std::collections::HashMap;

pub fn build_vocab(texts: &[&str]) -> HashMap<String, usize> {
    let mut vocab = HashMap::new();
    for text in texts {
        for token in text.to_lowercase().split_whitespace() {
            if !vocab.contains_key(token) {
                let id = vocab.len();
                vocab.insert(token.to_string(), id);
            }
        }
    }
    vocab
}

pub fn tokenize(text: &str, vocab: &HashMap<String, usize>) -> Vec<usize> {
    text.to_lowercase()
        .split_whitespace()
        .filter_map(|tok| vocab.get(tok).copied())
        .collect()
}

from __future__ import annotations


def _greedy_subword_count(word: str, subword_vocab: set[str]) -> int:
    count = 0
    position = 0
    while position < len(word):
        longest = ""
        for token in subword_vocab:
            if word.startswith(token, position) and len(token) > len(longest):
                longest = token
        if longest:
            position += len(longest)
        else:
            position += 1
        count += 1
    return count


def compare_token_counts(text: str, subword_vocab: set[str]) -> tuple[int, int]:
    words = text.lower().split()
    word_count = len(words)
    subword_count = sum(_greedy_subword_count(word, subword_vocab) for word in words)
    return word_count, subword_count

fn softmax(row: &[f64]) -> Vec<f64> {
    let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = row.iter().map(|x| (x - m).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

fn matmul(a: &[Vec<f64>], b: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = b[0].len();
    let mut out = vec![vec![0.0; cols]; rows];
    for i in 0..rows {
        for j in 0..cols {
            let mut acc = 0.0;
            for k in 0..b.len() {
                acc += a[i][k] * b[k][j];
            }
            out[i][j] = acc;
        }
    }
    out
}

fn transpose(a: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = a[0].len();
    let mut out = vec![vec![0.0; rows]; cols];
    for i in 0..rows {
        for j in 0..cols {
            out[j][i] = a[i][j];
        }
    }
    out
}

fn relu(row: &[f64]) -> Vec<f64> {
    row.iter().map(|x| x.max(0.0)).collect()
}

fn self_attention(x: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let dk = x[0].len() as f64;
    let scores = matmul(x, &transpose(x));
    let scaled: Vec<Vec<f64>> = scores
        .iter()
        .map(|row| row.iter().map(|x| x / dk.sqrt()).collect())
        .collect();
    let weights: Vec<Vec<f64>> = scaled.iter().map(|row| softmax(row)).collect();
    matmul(&weights, x)
}

pub fn transformer_block(x: &[Vec<f64>], w1: &[Vec<f64>], w2: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let attn = self_attention(x);
    let mut res1 = x.to_vec();
    for i in 0..res1.len() {
        for j in 0..res1[0].len() {
            res1[i][j] += attn[i][j];
        }
    }
    let ffn_hidden = matmul(&res1, w1);
    let ffn_hidden: Vec<Vec<f64>> = ffn_hidden.iter().map(|row| relu(row)).collect();
    let ffn = matmul(&ffn_hidden, w2);
    let mut res2 = res1.clone();
    for i in 0..res2.len() {
        for j in 0..res2[0].len() {
            res2[i][j] += ffn[i][j];
        }
    }
    res2
}

from __future__ import annotations

import math
import re
import string


def normalize_answer(text: str) -> str:
    text = text.lower()
    text = "".join(character for character in text if character not in string.punctuation)
    text = re.sub(r"\b(a|an|the)\b", " ", text)
    return " ".join(text.split())


def normalized_vote_counts(answers: list[str]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for answer in answers:
        normalized = normalize_answer(answer)
        counts[normalized] = counts.get(normalized, 0) + 1
    return counts


def _sorted_vote_counts(answers: list[str]) -> list[int]:
    return sorted(normalized_vote_counts(answers).values(), reverse=True)


def answer_stability(answers: list[str]) -> float:
    if not answers:
        return 0.0
    if len(answers) == 1:
        return 1.0

    counts = normalized_vote_counts(answers)
    total = len(answers)
    agreeing_pairs = sum(count * (count - 1) for count in counts.values())
    return agreeing_pairs / (total * (total - 1))


def majority_vote_margin(answers: list[str]) -> float:
    counts = _sorted_vote_counts(answers)
    if not counts:
        return 0.0

    top_share = counts[0] / len(answers)
    runner_up_share = 0.0 if len(counts) == 1 else counts[1] / len(answers)
    return top_share - runner_up_share


def vote_entropy(answers: list[str]) -> float:
    if not answers:
        return 0.0

    counts = normalized_vote_counts(answers)
    total = len(answers)
    return -sum((count / total) * math.log(count / total) for count in counts.values())


def answer_uniqueness_rate(answers: list[str]) -> float:
    if not answers:
        return 0.0
    return len(normalized_vote_counts(answers)) / len(answers)


def candidate_diversity(answers: list[str]) -> float:
    return answer_uniqueness_rate(answers)


def top_vote_share(answers: list[str]) -> float:
    counts = _sorted_vote_counts(answers)
    if not counts:
        return 0.0
    return counts[0] / len(answers)


def consensus_disagreement_rate(answers: list[str]) -> float:
    return 1.0 - top_vote_share(answers)


def minority_cluster_entropy(answers: list[str]) -> float:
    counts = _sorted_vote_counts(answers)
    if len(counts) <= 1:
        return 0.0

    minority_sizes = counts[1:]
    minority_total = sum(minority_sizes)
    return -sum((size / minority_total) * math.log(size / minority_total) for size in minority_sizes)

pub fn conversion_rate(conversions: i32, trials: i32) -> f64 {
    if trials > 0 { conversions as f64 / trials as f64 } else { 0.0 }
}

from __future__ import annotations


def backfill_replay_metrics(
    logged_requests: int,
    replayed_requests: int,
    mismatched_outputs: int,
) -> tuple[float, float]:
    if logged_requests <= 0:
        raise ValueError("logged_requests must be positive")
    if not 0 <= replayed_requests <= logged_requests:
        raise ValueError("replayed_requests must satisfy 0 <= replayed_requests <= logged_requests")
    if not 0 <= mismatched_outputs <= replayed_requests:
        raise ValueError("mismatched_outputs must satisfy 0 <= mismatched_outputs <= replayed_requests")

    coverage = replayed_requests / logged_requests
    mismatch_rate = 0.0 if replayed_requests == 0 else mismatched_outputs / replayed_requests
    return coverage, mismatch_rate

from __future__ import annotations


def batch_fill_rate(batch_sizes: list[int], max_batch_size: int) -> float:
    if max_batch_size <= 0:
        raise ValueError("max_batch_size must be positive")
    if any(batch_size < 0 for batch_size in batch_sizes):
        raise ValueError("batch_sizes must be non-negative")
    if any(batch_size > max_batch_size for batch_size in batch_sizes):
        raise ValueError("batch_sizes cannot exceed max_batch_size")
    if not batch_sizes:
        return 0.0

    average_batch_size = sum(batch_sizes) / len(batch_sizes)
    return average_batch_size / max_batch_size

