def psi(expected: list[float], actual: list[float]) -> float:
    total = 0.0
    for e, a in zip(expected, actual):
        if e > 0 and a > 0:
            total += (a - e) * math.log(a / e)
    return total

pub fn psi(expected: &[f64], actual: &[f64]) -> f64 {
    let mut total = 0.0;
    for (&e, &a) in expected.iter().zip(actual.iter()) {
        if e > 0.0 && a > 0.0 {
            total += (a - e) * (a / e).ln();
        }
    }
    total
}

