def bernoulli_log_likelihood(x: list[int], prob: list[float]) -> float:
    if len(x) != len(prob):
        raise ValueError("x and prob must have the same length")

    ll = 0.0
    for xi, p in zip(x, prob):
        if xi not in (0, 1):
            raise ValueError("x must contain only binary values")
        if not 0.0 < p < 1.0:
            raise ValueError("probabilities must be strictly between 0 and 1")
        ll += xi * math.log(p) + (1 - xi) * math.log(1 - p)
    return ll

pub fn bernoulli_log_likelihood(x: &[i32], prob: &[f64]) -> f64 {
    let mut ll = 0.0;
    for (&xi, &p) in x.iter().zip(prob.iter()) {
        ll += (xi as f64) * p.ln() + (1.0 - xi as f64) * (1.0 - p).ln();
    }
    ll
}

def neighbors(points: list[list[float]], idx: int, eps: float) -> list[int]:
    base = points[idx]
    out = []
    for i, p in enumerate(points):
        dist = sum((a - b) ** 2 for a, b in zip(base, p)) ** 0.5
        if dist <= eps:
            out.append(i)
    return out

pub fn neighbors(points: &[Vec<f64>], idx: usize, eps: f64) -> Vec<usize> {
    let base = &points[idx];
    let mut out = Vec::new();
    for (i, p) in points.iter().enumerate() {
        let dist = base
            .iter()
            .zip(p.iter())
            .map(|(a, b)| (a - b).powi(2))
            .sum::<f64>()
            .sqrt();
        if dist <= eps {
            out.push(i);
        }
    }
    out
}

