import math


def _harmonic_number(n: int) -> float:
    return sum(1.0 / k for k in range(1, n + 1))


def average_path_length(sample_size: int) -> float:
    if sample_size <= 1:
        return 0.0
    return 2.0 * _harmonic_number(sample_size - 1) - (2.0 * (sample_size - 1) / sample_size)


def isolation_score(avg_path_length: float, sample_size: int) -> float:
    if avg_path_length < 0.0:
        raise ValueError("avg_path_length must be non-negative")
    if sample_size <= 1:
        raise ValueError("sample_size must be greater than 1")

    normalizer = average_path_length(sample_size)
    return 2.0 ** (-avg_path_length / normalizer)

def assign(points: list[list[float]], centroids: list[list[float]]) -> list[int]:
    assignments = []
    for p in points:
        dists = [sum((pi - ci) ** 2 for pi, ci in zip(p, c)) for c in centroids]
        assignments.append(min(range(len(dists)), key=lambda i: dists[i]))
    return assignments

pub fn assign(points: &[Vec<f64>], centroids: &[Vec<f64>]) -> Vec<usize> {
    let mut assignments = Vec::with_capacity(points.len());
    for p in points {
        let mut best = 0;
        let mut best_dist = f64::INFINITY;
        for (i, c) in centroids.iter().enumerate() {
            let dist: f64 = p.iter().zip(c.iter()).map(|(pi, ci)| (pi - ci).powi(2)).sum();
            if dist < best_dist {
                best_dist = dist;
                best = i;
            }
        }
        assignments.push(best);
    }
    assignments
}

