def predict_proba(x: list[float], w: list[float], b: float) -> float:
    z = sum(wi * xi for wi, xi in zip(w, x)) + b
    return 1 / (1 + math.exp(-z))

pub fn predict_proba(x: &[f64], w: &[f64], b: f64) -> f64 {
    let mut z = b;
    for (wi, xi) in w.iter().zip(x.iter()) {
        z += wi * xi;
    }
    1.0 / (1.0 + (-z).exp())
}

pub fn bootstrap_indices(n: usize, seed: u64) -> Vec<usize> {
    let mut idxs = Vec::with_capacity(n);
    let mut state = seed;
    for _ in 0..n {
        state = (1103515245u64.wrapping_mul(state).wrapping_add(12345)) % (1u64 << 31);
        idxs.push((state as usize) % n);
    }
    idxs
}

pub fn softmax(logits: &[f64]) -> Vec<f64> {
    let m = logits.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = logits.iter().map(|x| (x - m).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

fn dot(a: &[f64], b: &[f64]) -> f64 {
    a.iter().zip(b.iter()).map(|(x, y)| x * y).sum()
}

fn sqdist(a: &[f64], b: &[f64]) -> f64 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let d = x - y;
            d * d
        })
        .sum()
}

pub fn pegasos_kernel_svm(
    data: &[Vec<f64>],
    labels: &[f64],
    kernel: &str,
    lambda_val: f64,
    iterations: usize,
    sigma: f64,
) -> (Vec<f64>, f64) {
    let n = data.len();
    assert_eq!(
        labels.len(),
        n,
        "labels must be shape (n_samples,), got {}",
        labels.len()
    );
    if n == 0 {
        return (Vec::new(), 0.0);
    }

    let d = data[0].len();
    for row in data.iter().skip(1) {
        assert_eq!(row.len(), d, "all rows in data must have the same length");
    }

    assert!(
        kernel == "linear" || kernel == "rbf",
        "kernel must be 'linear' or 'rbf'"
    );
    assert!(lambda_val > 0.0, "lambda_val must be > 0");
    assert!(iterations > 0, "iterations must be > 0");
    if kernel == "rbf" {
        assert!(sigma > 0.0, "sigma must be > 0 for rbf kernel");
    }

    // Precompute kernel matrix K (n x n)
    let mut k_mat = vec![vec![0.0; n]; n];
    if kernel == "linear" {
        for i in 0..n {
            for j in 0..n {
                k_mat[i][j] = dot(&data[i], &data[j]);
            }
        }
    } else {
        let denom = 2.0 * sigma * sigma;
        for i in 0..n {
            for j in 0..n {
                let dist2 = sqdist(&data[i], &data[j]).max(0.0);
                k_mat[i][j] = (-dist2 / denom).exp();
            }
        }
    }

    let mut alpha = vec![0.0; n];
    let mut b = 0.0;

    for t in 1..=iterations {
        let eta = 1.0 / (lambda_val * t as f64);

        // Deterministic: fixed order, full pass over all samples
        for i in 0..n {
            // f(x_i) = sum_j alpha_j * y_j * K(x_j, x_i) + b
            let mut f_i = b;
            for j in 0..n {
                f_i += alpha[j] * labels[j] * k_mat[j][i];
            }

            if labels[i] * f_i < 1.0 {
                alpha[i] = alpha[i] + eta * (labels[i] - lambda_val * alpha[i]);
                b += eta * labels[i];
            }
        }
    }

    (alpha, b)
}

from __future__ import annotations


def tsne_point_gradient(
    point: list[float],
    other_points: list[list[float]],
    affinities: list[float],
) -> list[float]:
    if len(other_points) != len(affinities):
        raise ValueError("other_points and affinities must have the same length")
    if any(len(other) != len(point) for other in other_points):
        raise ValueError("other_points must match the point dimension")
    if any(affinity < 0.0 for affinity in affinities):
        raise ValueError("affinities must be non-negative")
    if not other_points:
        return [0.0] * len(point)

    affinity_sum = sum(affinities)
    if affinity_sum <= 0.0:
        raise ValueError("affinities must sum to a positive value")
    normalized_affinities = [affinity / affinity_sum for affinity in affinities]

    numerators = []
    for other in other_points:
        squared_distance = sum((a - b) ** 2 for a, b in zip(point, other))
        numerators.append(1.0 / (1.0 + squared_distance))

    q_sum = sum(numerators)
    q_values = [numerator / q_sum for numerator in numerators]

    gradient = [0.0] * len(point)
    for p_ij, q_ij, numerator, other in zip(
        normalized_affinities, q_values, numerators, other_points
    ):
        coefficient = 4.0 * (p_ij - q_ij) * numerator
        for dimension in range(len(point)):
            gradient[dimension] += coefficient * (point[dimension] - other[dimension])
    return gradient

pub fn adagrad_step(w: f64, grad: f64, g2: f64, lr: f64, eps: f64) -> (f64, f64) {
    let g2_new = g2 + grad * grad;
    let w_new = w - lr * grad / (g2_new.sqrt() + eps);
    (w_new, g2_new)
}

pub fn adam_step(w: f64, grad: f64, m: f64, v: f64, lr: f64, beta1: f64, beta2: f64, eps: f64) -> (f64, f64, f64) {
    let m_new = beta1 * m + (1.0 - beta1) * grad;
    let v_new = beta2 * v + (1.0 - beta2) * grad * grad;
    let w_new = w - lr * m_new / (v_new.sqrt() + eps);
    (w_new, m_new, v_new)
}

pub fn adamw_step(w: f64, grad: f64, m: f64, v: f64, lr: f64, wd: f64, beta1: f64, beta2: f64, eps: f64) -> (f64, f64, f64) {
    let m_new = beta1 * m + (1.0 - beta1) * grad;
    let v_new = beta2 * v + (1.0 - beta2) * grad * grad;
    let w_new = w - lr * m_new / (v_new.sqrt() + eps) - lr * wd * w;
    (w_new, m_new, v_new)
}

