"""Muon optimizer demo using Gram-Schmidt orthogonalization."""

from __future__ import annotations

import math
from typing import List, Tuple


Matrix = List[List[float]]


def _dot(a: List[float], b: List[float]) -> float:
    return sum(x * y for x, y in zip(a, b))


def _norm(v: List[float]) -> float:
    return math.sqrt(_dot(v, v))


def gram_schmidt_rows(mat: Matrix, eps: float = 1e-12) -> Matrix:
    """Return an orthonormalized copy of rows via Gram-Schmidt."""
    out: Matrix = []
    for row in mat:
        v = row[:]
        for u in out:
            proj = _dot(v, u)
            v = [vi - proj * ui for vi, ui in zip(v, u)]
        n = _norm(v)
        if n < eps:
            out.append([0.0 for _ in v])
        else:
            out.append([vi / n for vi in v])
    return out


def muon_step(
    weights: Matrix,
    grad: Matrix,
    velocity: Matrix | None,
    lr: float = 0.1,
    momentum: float = 0.9,
) -> Tuple[Matrix, Matrix]:
    """Apply a Muon-style update and return (new_weights, new_velocity)."""
    if velocity is None:
        velocity = [[0.0 for _ in row] for row in grad]
    new_velocity = [
        [momentum * v + g for v, g in zip(v_row, g_row)]
        for v_row, g_row in zip(velocity, grad)
    ]
    ortho = gram_schmidt_rows(new_velocity)
    new_weights = [
        [w - lr * u for w, u in zip(w_row, u_row)]
        for w_row, u_row in zip(weights, ortho)
    ]
    return new_weights, new_velocity

pub type Matrix = Vec<Vec<f64>>;

fn dot(a: &[f64], b: &[f64]) -> f64 {
    a.iter().zip(b.iter()).map(|(x, y)| x * y).sum()
}

fn norm(v: &[f64]) -> f64 {
    dot(v, v).sqrt()
}

pub fn gram_schmidt_rows(mat: &Matrix, eps: f64) -> Matrix {
    let mut out: Matrix = Vec::new();
    for row in mat.iter() {
        let mut v = row.clone();
        for u in out.iter() {
            let proj = dot(&v, u);
            for (vi, ui) in v.iter_mut().zip(u.iter()) {
                *vi -= proj * ui;
            }
        }
        let n = norm(&v);
        if n < eps {
            out.push(vec![0.0; v.len()]);
        } else {
            out.push(v.iter().map(|vi| vi / n).collect());
        }
    }
    out
}

pub fn muon_step(
    weights: &Matrix,
    grad: &Matrix,
    velocity: Option<&Matrix>,
    lr: f64,
    momentum: f64,
) -> (Matrix, Matrix) {
    let mut vel = match velocity {
        Some(v) => v.clone(),
        None => grad.iter().map(|row| vec![0.0; row.len()]).collect(),
    };
    for (v_row, g_row) in vel.iter_mut().zip(grad.iter()) {
        for (v, g) in v_row.iter_mut().zip(g_row.iter()) {
            *v = momentum * *v + *g;
        }
    }
    let ortho = gram_schmidt_rows(&vel, 1e-12);
    let mut new_weights = weights.clone();
    for (w_row, u_row) in new_weights.iter_mut().zip(ortho.iter()) {
        for (w, u) in w_row.iter_mut().zip(u_row.iter()) {
            *w -= lr * u;
        }
    }
    (new_weights, vel)
}

pub fn nesterov_step(w: f64, grad: f64, v: f64, lr: f64, mu: f64) -> (f64, f64) {
    let v_new = mu * v + grad;
    let w_new = w - lr * (mu * v_new + grad);
    (w_new, v_new)
}

from __future__ import annotations

import math


def one_cycle_lr(
    max_lr: float,
    step: int,
    total_steps: int,
    pct_start: float = 0.3,
    div_factor: float = 25.0,
    final_div_factor: float = 1.0e4,
) -> float:
    if max_lr <= 0.0:
        raise ValueError("max_lr must be positive")
    if step < 0:
        raise ValueError("step must be non-negative")
    if total_steps <= 0:
        raise ValueError("total_steps must be positive")
    if not 0.0 < pct_start < 1.0:
        raise ValueError("pct_start must satisfy 0 < pct_start < 1")
    if div_factor <= 0.0 or final_div_factor <= 0.0:
        raise ValueError("div_factor and final_div_factor must be positive")

    if total_steps == 1:
        return max_lr

    initial_lr = max_lr / div_factor
    final_lr = initial_lr / final_div_factor
    last_step = total_steps - 1
    step = min(step, last_step)
    up_steps = max(1, int(last_step * pct_start))

    if step <= up_steps:
        progress = step / up_steps
        return initial_lr + progress * (max_lr - initial_lr)

    down_steps = last_step - up_steps
    progress = (step - up_steps) / down_steps
    cosine_weight = 0.5 * (1.0 + math.cos(math.pi * progress))
    return final_lr + cosine_weight * (max_lr - final_lr)

pub fn rmsprop_step(w: f64, grad: f64, v: f64, lr: f64, beta: f64, eps: f64) -> (f64, f64) {
    let v_new = beta * v + (1.0 - beta) * grad * grad;
    let w_new = w - lr * grad / (v_new.sqrt() + eps);
    (w_new, v_new)
}

pub fn momentum_step(w: f64, grad: f64, v: f64, lr: f64, mu: f64) -> (f64, f64) {
    let v_new = mu * v + grad;
    let w_new = w - lr * v_new;
    (w_new, v_new)
}

pub fn sgd_step(w: f64, grad: f64, lr: f64) -> f64 {
